            count(*) FILTER (WHERE date_part('hour'::text, ((trazabilidad_ms.pintura_fecha AT TIME ZONE 'UTC') AT TIME ZONE 'America/Bogota')) = 22::double precision) AS h22,
            count(*) FILTER (WHERE date_part('hour'::text, ((trazabilidad_ms.pintura_fecha AT TIME ZONE 'UTC') AT TIME ZONE 'America/Bogota')) = 23::double precision) AS h23
           FROM trazabilidad_ms
          WHERE ((trazabilidad_ms.pintura_fecha AT TIME ZONE 'UTC') AT TIME ZONE 'America/Bogota')::date = (now() AT TIME ZONE 'America/Bogota'::text)::date AND trazabilidad_ms.pintura_linea = 'Linea 2'::lineas_type
        UNION ALL
         SELECT 'Total Pintura'::text AS proceso,
            count(*) FILTER (WHERE date_part('hour'::text, ((trazabilidad_ms.pintura_fecha AT TIME ZONE 'UTC') AT TIME ZONE 'America/Bogota')) = 6::double precision) AS h6,
            count(*) FILTER (WHERE date_part('hour'::text, ((trazabilidad_ms.pintura_fecha AT TIME ZONE 'UTC') AT TIME ZONE 'America/Bogota')) = 7::double precision) AS h7,
            count(*) FILTER (WHERE date_part('hour'::text, ((trazabilidad_ms.pintura_fecha AT TIME ZONE 'UTC') AT TIME ZONE 'America/Bogota')) = 8::double precision) AS h8,
            count(*) FILTER (WHERE date_part('hour'::text, ((trazabilidad_ms.pintura_fecha AT TIME ZONE 'UTC') AT TIME ZONE 'America/Bogota')) = 9::double precision) AS h9,
            count(*) FILTER (WHERE date_part('hour'::text, ((trazabilidad_ms.pintura_fecha AT TIME ZONE 'UTC') AT TIME ZONE 'America/Bogota')) = 10::double precision) AS h10,
            count(*) FILTER (WHERE date_part('hour'::text, ((trazabilidad_ms.pintura_fecha AT TIME ZONE 'UTC') AT TIME ZONE 'America/Bogota')) = 11::double precision) AS h11,
            count(*) FILTER (WHERE date_part('hour'::text, ((trazabilidad_ms.pintura_fecha AT TIME ZONE 'UTC') AT TIME ZONE 'America/Bogota')) = 12::double precision) AS h12,
            count(*) FILTER (WHERE date_part('hour'::text, ((trazabilidad_ms.pintura_fecha AT TIME ZONE 'UTC') AT TIME ZONE 'America/Bogota')) = 13::double precision) AS h13,
            count(*) FILTER (WHERE date_part('hour'::text, ((trazabilidad_ms.pintura_fecha AT TIME ZONE 'UTC') AT TIME ZONE 'America/Bogota')) = 14::double precision) AS h14,
            count(*) FILTER (WHERE date_part('hour'::text, ((trazabilidad_ms.pintura_fecha AT TIME ZONE 'UTC') AT TIME ZONE 'America/Bogota')) = 15::double precision) AS h15,
            count(*) FILTER (WHERE date_part('hour'::text, ((trazabilidad_ms.pintura_fecha AT TIME ZONE 'UTC') AT TIME ZONE 'America/Bogota')) = 16::double precision) AS h16,
            count(*) FILTER (WHERE date_part('hour'::text, ((trazabilidad_ms.pintura_fecha AT TIME ZONE 'UTC') AT TIME ZONE 'America/Bogota')) = 17::double precision) AS h17,
            count(*) FILTER (WHERE date_part('hour'::text, ((trazabilidad_ms.pintura_fecha AT TIME ZONE 'UTC') AT TIME ZONE 'America/Bogota')) >= 6::double precision AND date_part('hour'::text, ((trazabilidad_ms.pintura_fecha AT TIME ZONE 'UTC') AT TIME ZONE 'America/Bogota')) <= 23::double precision) AS total_dia,
            round(count(*) FILTER (WHERE date_part('hour'::text, ((trazabilidad_ms.pintura_fecha AT TIME ZONE 'UTC') AT TIME ZONE 'America/Bogota')) >= 6::double precision AND date_part('hour'::text, ((trazabilidad_ms.pintura_fecha AT TIME ZONE 'UTC') AT TIME ZONE 'America/Bogota')) <= 23::double precision)::numeric / 18::numeric, 2) AS promedio,
            count(*) FILTER (WHERE date_part('hour'::text, ((trazabilidad_ms.pintura_fecha AT TIME ZONE 'UTC') AT TIME ZONE 'America/Bogota')) = 18::double precision) AS h18,
            count(*) FILTER (WHERE date_part('hour'::text, ((trazabilidad_ms.pintura_fecha AT TIME ZONE 'UTC') AT TIME ZONE 'America/Bogota')) = 19::double precision) AS h19,
