            count(*) FILTER (WHERE date_part('hour'::text, ((trazabilidad_ms.pintura_fecha AT TIME ZONE 'UTC') AT TIME ZONE 'America/Bogota')) = 22::double precision) AS h22,
            count(*) FILTER (WHERE date_part('hour'::text, ((trazabilidad_ms.pintura_fecha AT TIME ZONE 'UTC') AT TIME ZONE 'America/Bogota')) = 23::double precision) AS h23
           FROM trazabilidad_ms
          WHERE ((trazabilidad_ms.pintura_fecha AT TIME ZONE 'UTC') AT TIME ZONE 'America/Bogota')::date = (now() AT TIME ZONE 'America/Bogota'::text)::date
        UNION ALL
         SELECT 'Vaciado'::text AS proceso,
            count(*) FILTER (WHERE date_part('hour'::text, ((trazabilidad_ms.vaciado_fecha AT TIME ZONE 'UTC') AT TIME ZONE 'America/Bogota')) = 6::double precision) AS h6,
            count(*) FILTER (WHERE date_part('hour'::text, ((trazabilidad_ms.vaciado_fecha AT TIME ZONE 'UTC') AT TIME ZONE 'America/Bogota')) = 7::double precision) AS h7,
            count(*) FILTER (WHERE date_part('hour'::text, ((trazabilidad_ms.vaciado_fecha AT TIME ZONE 'UTC') AT TIME ZONE 'America/Bogota')) = 8::double precision) AS h8,
            count(*) FILTER (WHERE date_part('hour'::text, ((trazabilidad_ms.vaciado_fecha AT TIME ZONE 'UTC') AT TIME ZONE 'America/Bogota')) = 9::double precision) AS h9,
            count(*) FILTER (WHERE date_part('hour'::text, ((trazabilidad_ms.vaciado_fecha AT TIME ZONE 'UTC') AT TIME ZONE 'America/Bogota')) = 10::double precision) AS h10,
            count(*) FILTER (WHERE date_part('hour'::text, ((trazabilidad_ms.vaciado_fecha AT TIME ZONE 'UTC') AT TIME ZONE 'America/Bogota')) = 11::double precision) AS h11,
            count(*) FILTER (WHERE date_part('hour'::text, ((trazabilidad_ms.vaciado_fecha AT TIME ZONE 'UTC') AT TIME ZONE 'America/Bogota')) = 12::double precision) AS h12,
