            round(count(*) FILTER (WHERE date_part('hour'::text, ((trazabilidad_ms.vaciado_fecha AT TIME ZONE 'UTC') AT TIME ZONE 'America/Bogota')) >= 6::double precision AND date_part('hour'::text, ((trazabilidad_ms.vaciado_fecha AT TIME ZONE 'UTC') AT TIME ZONE 'America/Bogota')) <= 23::double precision)::numeric / 18::numeric, 2) AS promedio,
            count(*) FILTER (WHERE date_part('hour'::text, ((trazabilidad_ms.vaciado_fecha AT TIME ZONE 'UTC') AT TIME ZONE 'America/Bogota')) = 18::double precision) AS h18,
            count(*) FILTER (WHERE date_part('hour'::text, ((trazabilidad_ms.vaciado_fecha AT TIME ZONE 'UTC') AT TIME ZONE 'America/Bogota')) = 19::double precision) AS h19,
            count(*) FILTER (WHERE date_part('hour'::text, ((trazabilidad_ms.vaciado_fecha AT TIME ZONE 'UTC') AT TIME ZONE 'America/Bogota')) = 20::double precision) AS h20,
