        UNION ALL
         SELECT 'Linea 3'::text AS proceso,
            count(*) FILTER (WHERE date_part('hour'::text, ((trazabilidad_ms.pintura_fecha AT TIME ZONE 'UTC') AT TIME ZONE 'America/Bogota')) = 6::double precision) AS h6,
            count(*) FILTER (WHERE date_part('hour'::text, ((trazabilidad_ms.pintura_fecha AT TIME ZONE 'UTC') AT TIME ZONE 'America/Bogota')) = 7::double precision) AS h7,
            count(*) FILTER (WHERE date_part('hour'::text, ((trazabilidad_ms.pintura_fecha AT TIME ZONE 'UTC') AT TIME ZONE 'America/Bogota')) = 8::double precision) AS h8,
            count(*) FILTER (WHERE date_part('hour'::text, ((trazabilidad_ms.pintura_fecha AT TIME ZONE 'UTC') AT TIME ZONE 'America/Bogota')) = 9::double precision) AS h9,
            count(*) FILTER (WHERE date_part('hour'::text, ((trazabilidad_ms.pintura_fecha AT TIME ZONE 'UTC') AT TIME ZONE 'America/Bogota')) = 10::double precision) AS h10,
